import{_ as i,o,c as l,ak as a}from"./chunks/framework.Dpc0wyhY.js";const u=JSON.parse('{"title":"Profiles","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/users/profiles.md","filePath":"grindr-api/users/profiles.md"}'),s={name:"grindr-api/users/profiles.md"};function r(t,e,d,n,c,h){return o(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to “Profiles”">​</a></h1><h2 id="rectf" tabindex="-1">RectF <a class="header-anchor" href="#rectf" aria-label="Permalink to “RectF”">​</a></h2><p>Array of 4 floats or <code>nulls</code>:</p><ul><li>Bottom edge (&quot;y2&quot;), in pixels</li><li>Left edge (&quot;x1&quot;), in pixels</li><li>Right edge (&quot;x2&quot;), in pixels</li><li>Top edge (&quot;y1&quot;), in pixels</li></ul><p>When used in query, stringified as follows: <code>y2,x1,x2,y1</code>.</p><h2 id="profilemaskedmin" tabindex="-1">ProfileMaskedMin <a class="header-anchor" href="#profilemaskedmin" aria-label="Permalink to “ProfileMaskedMin”">​</a></h2><ul><li><code>distance</code> — number or <code>null</code></li><li><code>profileImageMediaHash</code> — string or <code>null</code>, see <a href="/grindr-api/media/index#media">Media</a></li><li><code>isFavorite</code> — boolean</li></ul><h2 id="profilemasked" tabindex="-1">ProfileMasked <a class="header-anchor" href="#profilemasked" aria-label="Permalink to “ProfileMasked”">​</a></h2><ul><li><em>everything from <a href="#profilemaskedmin">ProfileMaskedMin</a></em></li><li><code>lastViewed</code> — number or <code>null</code></li><li><code>seen</code> — unix timestamp in milliseconds or <code>null</code></li><li><code>sexualPosition</code> — integer or <code>null</code>, see <a href="#sexual-position-id">Sexual position ID</a></li><li><code>foundVia</code> — <a href="/grindr-api/interest/views#viewsourceenum">ViewSourceEnum</a> or <code>null</code></li><li><code>rightNow</code> — <a href="/grindr-api/right-now#rightnowstatus">RightNowStatus</a></li></ul><h2 id="profilemin" tabindex="-1">ProfileMin <a class="header-anchor" href="#profilemin" aria-label="Permalink to “ProfileMin”">​</a></h2><ul><li><code>profileId</code> — string with numeric id</li><li><code>displayName</code> — string or <code>null</code></li><li><code>onlineUntil</code> — long number or <code>null</code></li></ul><h2 id="profileshort" tabindex="-1">ProfileShort <a class="header-anchor" href="#profileshort" aria-label="Permalink to “ProfileShort”">​</a></h2><ul><li><em>everything from <a href="#profilemasked">ProfileMasked</a></em></li><li><em>everything from <a href="#profilemin">ProfileMin</a></em></li><li><code>age</code> — number, may be <code>0</code> or <code>null</code></li><li><code>showAge</code> — boolean</li><li><code>showDistance</code> — boolean</li><li><code>approximateDistance</code> — boolean</li><li><code>lastChatTimestamp</code> — number, may be <code>0</code></li><li><code>isNew</code> — boolean</li><li><code>lastUpdatedTime</code> — unix timestamp in milliseconds, may be <code>0</code></li><li><code>medias</code> — array of profile photos objects <ul><li><code>mediaHash</code> — string, see <a href="/grindr-api/media/index#media">Media</a></li><li><code>type</code> — integer</li><li><code>state</code> — integer</li><li><code>reason</code> — string or <code>null</code></li><li><code>takenOnGrindr</code> — boolean or <code>null</code></li><li><code>createdAt</code> — long number or <code>null</code></li></ul></li></ul><h2 id="profilefields" tabindex="-1">ProfileFields <a class="header-anchor" href="#profilefields" aria-label="Permalink to “ProfileFields”">​</a></h2><ul><li><code>meetAt</code> — array of integers, see <a href="#meet-at">Meet at</a></li><li><code>vaccines</code> — array of integers, see <a href="#vaccines">Vaccines</a></li><li><code>genders</code> — array of integers, see <a href="#genders">Genders</a></li><li><code>pronouns</code> — array of integers, see <a href="#pronouns">Pronouns</a></li></ul><h2 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to “Profile”">​</a></h2><ul><li><em>everything from <a href="#profileshort">ProfileShort</a></em></li><li><em>everything from <a href="#profilefields">ProfileFields</a></em></li><li><code>aboutMe</code> — string or <code>null</code></li><li><code>ethnicity</code> — integer or <code>null</code>, see <a href="#ethnicity">Ethnicity</a></li><li><code>relationshipStatus</code> — integer or <code>null</code>, see <a href="#relationship-status">Relationship status</a></li><li><code>grindrTribes</code> — array of integers, see <a href="#tribes">Tribes</a></li><li><code>lookingFor</code> — array of integers, see <a href="#looking-for">Looking for</a></li><li><code>bodyType</code> — number or <code>null</code>, see <a href="#body-type">Body type</a></li><li><code>hivStatus</code> — number or <code>null</code>, see <a href="#hiv-status">HIV status</a></li><li><code>lastTestedDate</code> — unix timestamp in milliseconds or <code>null</code></li><li><code>height</code> — number or <code>null</code></li><li><code>weight</code> — number or <code>null</code></li><li><code>socialNetworks</code> — object <ul><li><code>twitter</code> — object, may be absent <ul><li><code>userId</code> — string or <code>null</code></li></ul></li><li><code>facebook</code> — object, may be absent <ul><li><code>userId</code> — string or <code>null</code></li></ul></li><li><code>instagram</code> — object, may be absent <ul><li><code>userId</code> — string or <code>null</code></li></ul></li></ul></li><li><code>identity</code> — identity (unknown, wip) or <code>null</code></li><li><code>nsfw</code> — integer or <code>null</code>, see <a href="#accept-nsfw-pics">Accept NSFW pics</a></li><li><code>hashtags</code> — unknown array</li><li><code>profileTags</code> — array of strings, see <a href="#profile-tags">Profile tags</a></li><li><code>tapped</code> — boolean</li><li><code>tapType</code> — boolean</li><li><code>lastReceivedTapTimestamp</code> — number or <code>null</code></li><li><code>isTeleporting</code> — boolean</li><li><code>isRoaming</code> — boolean</li><li><code>arrivalDays</code> — number or <code>null</code></li><li><code>unreadCount</code> — number, may be absent</li><li><code>rightNowText</code> — string or <code>null</code></li><li><code>rightNowPosted</code> — long number or <code>null</code></li><li><code>rightNowDistance</code> — long number or <code>null</code></li><li><code>rightNowThumbnailUrl</code> — string or <code>null</code></li><li><code>rightNowFullImageUrl</code> — string or <code>null</code></li><li><code>rightNowShareLocation</code> — <code>null</code></li><li><code>rightNowMedias</code> — array of objects <ul><li><code>mediaId</code> — long number or <code>null</code></li><li><code>thumbnailUrl</code> — string</li><li><code>fullImageUrl</code> — string</li><li><code>contentType</code> — string</li><li><code>isNsfw</code> — boolean or <code>null</code></li></ul></li><li><code>verifiedInstagramId</code> — string or <code>null</code></li><li><code>lastThrobTimestamp</code> — unknown</li><li><code>isBlockable</code> — boolean</li><li><code>sexualHealth</code> — array of integers, see <a href="#sexual-health">Sexual health</a></li><li><code>isVisiting</code> — boolean</li><li><code>travelPlans</code> — array of objects <ul><li><code>endDateUtc</code> — long or <code>null</code></li><li><code>geohash</code> — <a href="/grindr-api/browse/location#geohash">Geohash</a></li><li><code>id</code> — long number or <code>null</code></li><li><code>locationName</code> — string</li><li><code>showOnProfile</code> — boolean or <code>null</code></li><li><code>startDateUtc</code> — long number or <code>null</code></li></ul></li><li><code>isInAList</code> — boolean</li><li><code>showTribes</code> — boolean</li><li><code>showPosition</code> — boolean</li><li><code>tribesImInto</code> — null</li><li><code>showVipBadge</code> — boolean</li></ul><h2 id="profile-tags" tabindex="-1">Profile tags <a class="header-anchor" href="#profile-tags" aria-label="Permalink to “Profile tags”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/tags</span></span></code></pre></div><p>Response:</p><p>Array of objects:</p><ul><li><code>language</code> — string</li><li><code>categoryCollection</code> — array of objects <ul><li><code>text</code> — string</li><li><code>possessiveText</code> string or <code>null</code></li><li><code>tags</code> — array of objects <ul><li><code>tagId</code> — integer</li><li><code>text</code> — string</li><li><code>key</code> — string</li></ul></li></ul></li></ul><h2 id="sexual-position-id" tabindex="-1">Sexual position ID <a class="header-anchor" href="#sexual-position-id" aria-label="Permalink to “Sexual position ID”">​</a></h2><ul><li>1 — &quot;Top&quot;</li><li>2 — &quot;Bottom&quot;</li><li>3 — &quot;Versatile&quot;</li><li>4 — &quot;Vers Bottom&quot;</li><li>5 — &quot;Vers Top&quot;</li><li>6 — &quot;Side&quot;</li></ul><h2 id="ethnicity" tabindex="-1">Ethnicity <a class="header-anchor" href="#ethnicity" aria-label="Permalink to “Ethnicity”">​</a></h2><ul><li>1 — Asian</li><li>2 — Black</li><li>3 — Latino</li><li>4 — Middle Eastern</li><li>5 — Mixed</li><li>6 — Native American</li><li>7 — White</li><li>8 — Other</li><li>9 — South Asian</li></ul><h2 id="relationship-status" tabindex="-1">Relationship status <a class="header-anchor" href="#relationship-status" aria-label="Permalink to “Relationship status”">​</a></h2><ul><li>1 — Single</li><li>2 — Dating</li><li>3 — Exclusive</li><li>4 — Committed</li><li>5 — Partnered</li><li>6 — Engaged</li><li>7 — Married</li><li>8 — Open Relationship</li></ul><h2 id="body-type" tabindex="-1">Body type <a class="header-anchor" href="#body-type" aria-label="Permalink to “Body type”">​</a></h2><ul><li>1 — &quot;Toned&quot;</li><li>2 — &quot;Average&quot;</li><li>3 — &quot;Large&quot;</li><li>4 — &quot;Muscular&quot;</li><li>5 — &quot;Slim&quot;</li><li>6 — &quot;Stocky&quot;</li></ul><h2 id="hiv-status" tabindex="-1">HIV status <a class="header-anchor" href="#hiv-status" aria-label="Permalink to “HIV status”">​</a></h2><p>Not to be confused with <a href="#sexual-health">Sexual health</a>.</p><ul><li>1 — &quot;Negative&quot;</li><li>2 — &quot;Negative, on PrEP&quot;</li><li>3 — &quot;Positive&quot;</li><li>4 — &quot;Positive, undetectable&quot;</li></ul><h2 id="accept-nsfw-pics" tabindex="-1">Accept NSFW pics <a class="header-anchor" href="#accept-nsfw-pics" aria-label="Permalink to “Accept NSFW pics”">​</a></h2><ul><li>1 — &quot;Never&quot;</li><li>2 — &quot;Not At First&quot;</li><li>3 — &quot;Yes Please&quot;</li></ul><h2 id="meet-at" tabindex="-1">Meet at <a class="header-anchor" href="#meet-at" aria-label="Permalink to “Meet at”">​</a></h2><ul><li>1 — &quot;My Place&quot;</li><li>2 — &quot;Your Place&quot;</li><li>3 — &quot;Bar&quot;</li><li>4 — &quot;Coffee Shop&quot;</li><li>5 — &quot;Restaurant&quot;</li></ul><h2 id="sexual-health" tabindex="-1">Sexual health <a class="header-anchor" href="#sexual-health" aria-label="Permalink to “Sexual health”">​</a></h2><p>Not to be confused with <a href="#hiv-status">HIV status</a>.</p><ul><li>1 — &quot;Condoms&quot;</li><li>2 — &quot;I&#39;m on doxyPEP&quot;</li><li>3 — &quot;I&#39;m on PrEP&quot;</li><li>4 — &quot;I&#39;m HIV undetectable&quot;</li><li>5 — &quot;Prefer to discuss&quot;</li></ul><h2 id="looking-for" tabindex="-1">Looking for <a class="header-anchor" href="#looking-for" aria-label="Permalink to “Looking for”">​</a></h2><ul><li>2 — Chat</li><li>3 — Dates</li><li>4 — Friends</li><li>5 — Networking</li><li>6 — Relationship</li><li>7 — Hookups</li></ul><h2 id="tribes" tabindex="-1">Tribes <a class="header-anchor" href="#tribes" aria-label="Permalink to “Tribes”">​</a></h2><ul><li>1 — &quot;Bear&quot;</li><li>2 — &quot;Clean-Cut&quot;</li><li>3 — &quot;Daddy&quot;</li><li>4 — &quot;Discreet&quot;</li><li>5 — &quot;Geek&quot;</li><li>6 — &quot;Jock&quot;</li><li>7 — &quot;Leather&quot;</li><li>8 — &quot;Otter&quot;</li><li>9 — &quot;Poz&quot;</li><li>10 — &quot;Rugged&quot;</li><li>11 — &quot;Sober&quot;</li><li>12 — &quot;Trans&quot;</li><li>13 — &quot;Twink&quot;</li></ul><h2 id="vaccines" tabindex="-1">Vaccines <a class="header-anchor" href="#vaccines" aria-label="Permalink to “Vaccines”">​</a></h2><ul><li>1 - COVID-19</li><li>2 — Monkeypox</li><li>3 — Meningitis</li></ul><h2 id="socialnetwork" tabindex="-1">SocialNetwork <a class="header-anchor" href="#socialnetwork" aria-label="Permalink to “SocialNetwork”">​</a></h2><ul><li><code>site</code> — string, e.g. <code>&quot;twitter&quot;</code> | <code>&quot;facebook&quot;</code> | <code>&quot;instagram&quot;</code></li><li><code>userId</code> — string, username</li></ul><h2 id="managed-fields" tabindex="-1">Managed fields <a class="header-anchor" href="#managed-fields" aria-label="Permalink to “Managed fields”">​</a></h2><p>Managed fields, such as <a href="#get-genders">gender</a> and <a href="#get-pronouns">pronouns</a> are profile fields that aren&#39;t hardcoded but pulled dynamically from server.</p><h2 id="get-a-profile-by-id" tabindex="-1">Get a profile by ID <a class="header-anchor" href="#get-a-profile-by-id" aria-label="Permalink to “Get a profile by ID”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v7/profiles/{id}</span></span></code></pre></div><p>Query:</p><ul><li><code>id</code> — profile ID</li></ul><p>Response:</p><ul><li><code>profiles</code> - array of <a href="#profile">Profile</a>, always with exactly one element</li></ul><h2 id="get-multiple-profiles-by-id" tabindex="-1">Get multiple profiles by ID <a class="header-anchor" href="#get-multiple-profiles-by-id" aria-label="Permalink to “Get multiple profiles by ID”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v3/profiles</span></span></code></pre></div><p>Body:</p><ul><li><code>targetProfileIds</code> — array of strings with numeric ids</li></ul><p>Response:</p><ul><li><code>profiles</code> — array of <a href="#profile">Profile</a></li></ul><h2 id="update-own-profile-full" tabindex="-1">Update own profile (full) <a class="header-anchor" href="#update-own-profile-full" aria-label="Permalink to “Update own profile (full)”">​</a></h2><p>WIP</p><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PUT /v3.1/me/profile</span></span></code></pre></div><p>Body:</p><p><a href="#profile">Profile</a> object, fully replaces current version.</p><h2 id="update-own-profile-partial" tabindex="-1">Update own profile (partial) <a class="header-anchor" href="#update-own-profile-partial" aria-label="Permalink to “Update own profile (partial)”">​</a></h2><p>WIP</p><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PATCH /v4/me/profile</span></span></code></pre></div><p>Body:</p><p><a href="#profile">Profile</a> object, only updates specified keys.</p><h2 id="profile-tags-suggestions" tabindex="-1">Profile tags suggestions <a class="header-anchor" href="#profile-tags-suggestions" aria-label="Permalink to “Profile tags suggestions”">​</a></h2><p>See <a href="#profile-tags">Hardcoded fields -&gt; Profile tags</a>.</p><ul><li>PUT /v4/profile-tags/suggestions ProfileTagsSuggestionRequest</li><li>GET /v5/profile-tags/translations (header: L-Locale) . TranslationsResponse</li></ul><h2 id="upload-media" tabindex="-1">Upload media <a class="header-anchor" href="#upload-media" aria-label="Permalink to “Upload media”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v5/chat/media/upload</span></span></code></pre></div><p>Query:</p><ul><li><code>length</code> — long</li><li><code>looping</code> — boolean</li><li><code>takenOnGrindr</code> — boolean</li></ul><p>Body:</p><p>File</p><p>Correct request&#39;s <code>Content-Type</code> header is required.</p><p>Response:</p><ul><li><code>mediaId</code> — long integer</li><li><code>mediaHash</code> — string, see <a href="/grindr-api/media/signed-cdn-files">Media -&gt; Signed CDN files</a></li><li><code>url</code> — string, URL</li></ul><h2 id="upload-media-legacy" tabindex="-1">Upload media (legacy) <a class="header-anchor" href="#upload-media-legacy" aria-label="Permalink to “Upload media (legacy)”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/media/upload</span></span></code></pre></div><p><em>Also there is a legacy <code>POST /v3/me/profile/images</code>.</em></p><p>Query:</p><ul><li><code>thumbCoords</code> — <a href="#rectf">RectF</a>, see note below</li><li><code>takenOnGrindr</code> — boolean, only for v4 endpoint</li></ul><p>You must ensure thumbCoords&#39;s width and height dimensions are equal, i.e. y2-y1 must equal to x2-x1. Submitting non-suqare thumbnail won&#39;t trigger any errors and it will be uploaded to CDN, however attempting to use such illegal thumbnail dimensions image in <a href="#edit-profile-photos">Edit profile photos</a> will result in it being silently dropped/skipped.</p><p>Body:</p><p>Binary media file</p><p>Response:</p><ul><li><code>hash</code> — string</li><li><code>imageSizes</code> — array of objects <ul><li><code>size</code> — integer or <code>null</code></li><li><code>fullUrl</code> — string</li><li><code>thumbnail</code> — boolean or <code>null</code></li><li><code>state</code> — string, <a href="/grindr-api/media/signed-cdn-files#mediastate">MediaState</a></li><li><code>mediaHash</code> — string, see <a href="/grindr-api/media/public-cdn-files">Media -&gt; Public CDN files</a></li><li><code>rejectionReason</code> — string or <code>null</code></li></ul></li><li><code>mediaId</code> — integer</li></ul><h2 id="get-my-profile-photos" tabindex="-1">Get my profile photos <a class="header-anchor" href="#get-my-profile-photos" aria-label="Permalink to “Get my profile photos”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v3.1/me/profile/images</span></span></code></pre></div><p>Response:</p><ul><li><code>medias</code> — array of objects <ul><li><code>mediaHash</code> — string, see <a href="/grindr-api/media/public-cdn-files">Media -&gt; Public CDN files</a></li><li><code>type</code> — unknown integer</li><li><code>state</code> — integer, <a href="/grindr-api/media/signed-cdn-files#mediastate">MediaState</a>, WIP</li></ul></li></ul><h2 id="edit-profile-photos" tabindex="-1">Edit profile photos <a class="header-anchor" href="#edit-profile-photos" aria-label="Permalink to “Edit profile photos”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PUT /v3/me/profile/images</span></span></code></pre></div><p>Body:</p><ul><li><code>primaryImageHash</code> — string or <code>null</code>, see <a href="/grindr-api/media/public-cdn-files">Media -&gt; Public CDN file</a></li><li><code>secondaryImageHashes</code> — array (max. length: 5) of strings or <code>null</code> (note: see below), see <a href="/grindr-api/media/public-cdn-files">Media -&gt; Public CDN file</a></li></ul><p>Setting both <code>primaryImageHash</code> and <code>secondaryImageHashes</code> to <code>null</code> works. But setting <code>primaryImageHash</code> to a hash value while setting <code>secondaryImageHashes</code> to null causes HTTP status 400 Bad Request error. It&#39;s recommended to just use <code>[]</code> for <code>secondaryImageHashes</code> rather than <code>null</code>.</p><p>Supplied images must have square thumbnails, otherwise they will be silently skipped. See <a href="#upload-media">Upload media</a>.</p><p>Repeating <code>primaryImageHash</code> value in <code>secondaryImageHashes</code> array will result in secondaryImageHashes&#39;s entry being silently dropped from supplied request array. Repeating <code>secondaryImageHashes</code> values will result in successfully saving the array as-is to the server, however official mobile client seems to drop repeating media when processing <code>secondaryImageHashes</code> response.</p><p>Response:</p><p>Empty.</p><h2 id="delete-profile-photos" tabindex="-1">Delete profile photos <a class="header-anchor" href="#delete-profile-photos" aria-label="Permalink to “Delete profile photos”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>This endpoint removes photo from your profile as well as deletes the media from CDN.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>DELETE /v3/me/profile/images</span></span></code></pre></div><p>Body (yes, body, not query):</p><ul><li><code>media_hashes</code> — array of strings</li></ul><p>Response:</p><p>Empty.</p><h2 id="check-if-profiles-are-reachable" tabindex="-1">Check if profiles are reachable <a class="header-anchor" href="#check-if-profiles-are-reachable" aria-label="Permalink to “Check if profiles are reachable”">​</a></h2><p>WIP</p><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>POST /v4/profiles/reachable</span></span></code></pre></div><p>Body:</p><ul><li><code>profileIds</code> — array of strings with numeric ids</li></ul><p>Response:</p><ul><li><code>profileIds</code> — array of strings with numeric ids</li></ul><h2 id="get-profile-insights" tabindex="-1">Get profile insights <a class="header-anchor" href="#get-profile-insights" aria-label="Permalink to “Get profile insights”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/profile-insights/{profileId}</span></span></code></pre></div><p>Response: ProfileInsightsResponse, WIP</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v2/profile-insights/{profileId}</span></span></code></pre></div><p>Response: ProfileInsightsV2Response, WIP</p><h2 id="get-pronouns" tabindex="-1">Get pronouns <a class="header-anchor" href="#get-pronouns" aria-label="Permalink to “Get pronouns”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v1/pronouns</span></span></code></pre></div><p>Response:</p><p>Array of objects:</p><ul><li><code>pronounId</code> — integer</li><li><code>pronoun</code> — string, e.g. <code>&quot;-&quot;</code> or <code>&quot;They/Them/Theirs&quot;</code></li></ul><h2 id="get-genders" tabindex="-1">Get genders <a class="header-anchor" href="#get-genders" aria-label="Permalink to “Get genders”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /public/v2/genders</span></span></code></pre></div><p><em>Also aliased to <code>GET /public/v1/genders</code></em></p><p>Response:</p><p>Array of objects:</p><ul><li><code>genderId</code> — integer</li><li><code>gender</code> — string</li><li><code>displayGroup</code> — integer</li><li><code>sortProfile</code> — integer or <code>null</code></li><li><code>sortFilter</code> — integer or <code>null</code></li><li><code>genderPlural</code> — string or <code>null</code></li><li><code>excludeOnProfileSelection</code> — array of integers or <code>null</code></li><li><code>excludeOnFilterSelection</code> — array of integers or <code>null</code></li><li><code>alsoClassifiedAs</code> — array of integers</li></ul><h2 id="suggest-gender-or-pronoun" tabindex="-1">Suggest gender or pronoun <a class="header-anchor" href="#suggest-gender-or-pronoun" aria-label="Permalink to “Suggest gender or pronoun”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PUT /v4/genderpronoun/suggestions</span></span></code></pre></div><p>Body:</p><ul><li><code>category</code> — string, either <code>gender</code> or <code>pronoun</code></li><li><code>suggestedValue</code> — string</li></ul><p>Response:</p><p>Empty</p>',155)])])}const g=i(s,[["render",r]]);export{u as __pageData,g as default};
